long long solve(std::vector<std::vector<long long>> points) {
    long long count = 0;
    int n = points.size();
    // Map to store the slope between two points
    std::unordered_map<std::pair<long long, long long>, int> slopeMap;

    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            long long x1 = points[i][0], y1 = points[i][1];
            long long x2 = points[j][0], y2 = points[j][1];
            long long dx = x2 - x1, dy = y2 - y1;

            // Handle vertical lines (infinite slope)
            if (dx == 0) {
                slopeMap[std::make_pair(0, 1)]++;
            } else {
                // Simplify the slope to its reduced form
                long long gcd_val = std::gcd(dx, dy);
                long long reduced_dx = dx / gcd_val;
                long long reduced_dy = dy / gcd_val;
                // Ensure consistent representation (e.g., positive denominator)
                if (reduced_dx < 0) {
                    reduced_dx = -reduced_dx;
                    reduced_dy = -reduced_dy;
                }
                slopeMap[std::make_pair(reduced_dx, reduced_dy)]++;
            }
        }
    }

    // Count the number of pairs of points with the same slope
    for (auto& [slope, cnt] : slopeMap) {
        count += (long long)(cnt * (cnt - 1)) / 2;
    }

    return count;
}
